/**************************************************************************
 * IMPORTS
 ***************************************************************************/
import { CrispClass as Crisp } from "./index";
/**************************************************************************
 * TYPES
 ***************************************************************************/
export type FileMessage = {
    url: string;
    type: string;
    name: string;
};
export type AnimationMessage = {
    url: string;
    type: string;
};
export type AudioMessage = {
    url: string;
    type: string;
    duration: number;
};
export type PickerMessage = {
    id: string;
    text: string;
    choices: PickerMessageChoices[];
};
export type PickerMessageChoices = {
    value: string;
    label: string;
    selected: boolean;
};
export type FieldMessage = {
    id: string;
    text: string;
    explain: string;
};
export type CarouselMessageTargets = {
    title: string;
    description?: string;
    image?: string;
    actions: CarouselMessageTargetsActions[];
};
export type CarouselMessageTargetsActions = {
    label: string;
    url: string;
};
export type CarouselMessage = {
    text: string;
    targets: CarouselMessageTargets[];
};
/**************************************************************************
 * CLASS
 ***************************************************************************/
/**
 * Crisp message management
 */
export default class CrispMessage {
    private parent;
    /**
     * Constructor
     */
    constructor(crisp: Crisp);
    /**
     * Sets the message input text
     */
    setMessageText(content: string): void;
    /**
     * Sends a message
     */
    send(type: string, content: string | FileMessage | AnimationMessage | AudioMessage): void;
    /**
     * Sends a text message
     */
    sendText(content: string): void;
    /**
     * Sends a file message
     */
    sendFile(content: FileMessage): void;
    /**
     * Sends an animation message
     */
    sendAnimation(content: AnimationMessage): void;
    /**
     * Sends an audio message
     */
    sendAudio(content: AudioMessage): void;
    /**
     * Shows a message in the chat
     */
    show(type: string, content: string | FileMessage | AnimationMessage | AudioMessage | FieldMessage | PickerMessage | CarouselMessage): void;
    /**
     * Shows a text message
     */
    showText(content: string): void;
    /**
     * Shows a file message
     */
    showFile(content: FileMessage): void;
    /**
     * Shows an animation message
     */
    showAnimation(content: AnimationMessage): void;
    /**
     * Shows an audio message
     */
    showAudio(content: AudioMessage): void;
    /**
     * Shows a picker message
     */
    showPicker(content: PickerMessage): void;
    /**
     * Shows a field message
     */
    showField(content: FieldMessage): void;
    /**
     * Shows a carousel message
     */
    showCarousel(content: CarouselMessage): void;
    /**
     * Marks all messages as read
     */
    markAsRead(): void;
    /**
     * Starts a message thread
     */
    startThread(name: string): void;
    /**
     * Ends a message thread
     */
    endThread(name?: string): void;
    /**
     * Registers a callback for message sent event
     */
    onMessageSent(callback: Function): void;
    /**
     * Unregisters the message sent callback
     */
    offMessageSent(): void;
    /**
     * Registers a callback for message received event
     */
    onMessageReceived(callback: Function): void;
    /**
     * Unregisters the message received callback
     */
    offMessageReceived(): void;
    /**
     * Registers a callback for message compose sent event
     */
    onMessageComposeSent(callback: Function): void;
    /**
     * Unregisters the message compose sent callback
     */
    offMessageComposeSent(): void;
    /**
     * Registers a callback for message compose received event
     */
    onMessageComposeReceived(callback: Function): void;
    /**
     * Unregisters the message compose received callback
     */
    offMessageComposeReceived(): void;
}
